    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const projectService = require('./service');

router.get('/health', (req, res) => {
  res.json({ ok: true });
});

router.post('/', async (req, res) => {
  try {
    const project = await projectService.createProject(req.body);
    res.status(201).json(project);
  } catch (error) {
    res.status(error.code || 500).json({ error: { code: error.code, message: error.message } });
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('../../lib/id');
const { ProjectNotFoundError, DuplicateProjectError } = require('../../lib/errors');

class ProjectService {
  constructor() {
    this.projects = [];
  }

  async createProject(data) {
    const existingProject = this.projects.find(p => p.name === data.name);
    if (existingProject) {
      throw new DuplicateProjectError('Project already exists');
    }
    const project = { id: randomUUID(), name: data.name, members: [], tasks: [] };
    this.projects.push(project);
    return project;
  }

  async getProject(id) {
    const project = this.projects.find(p => p.id === id);
    if (!project) {
      throw new ProjectNotFoundError('Project not found');
    }
    return project;
  }
}

module.exports = new ProjectService();"
