    {
      "path": "src/lib/errors.js",
      "content": "class ProjectNotFoundError extends Error {
  constructor(message) {
    super(message);
    this.code = 404;
  }
}

class DuplicateProjectError extends Error {
  constructor(message) {
    super(message);
    this.code = 409;
  }
}

module.exports = { ProjectNotFoundError, DuplicateProjectError };"
